<template>
  <div class="order-wrap">
    <van-nav-bar
      fixed
      placeholder
      title="我的订单"
      left-text="返回"
      left-arrow
      @click-left="$router.go(-1)"
    />
    <van-tabs v-model="active" @click="switchTo">
      <van-tab title="全部"></van-tab>
      <van-tab title="待付款"></van-tab>
      <van-tab title="待发货"></van-tab>
      <van-tab title="已取消"></van-tab>
    </van-tabs>
    <div class="order-list">
      <div v-for="item in onList" :key="item.orderId" class="order mb-10">
        <router-link :to="`detail/${item.orderId}`">
          <van-card
            v-if="item.carts.length === 1"
            class="bg-fff"
            :num="item.carts[0].buyNum"
            :price="item.carts[0].price / 100"
            :title="item.carts[0].masterName"
            :thumb="item.carts[0].imgUrl"
          />
          <div v-else class="card bg-fff flex aic jc-sb">
            <div class="imgs flex aic">
              <img
                class="product-img mr-5"
                v-for="(good, index) in item.carts"
                :key="index"
                :src="good.imgUrl"
                alt=""
              />
            </div>
            <i class="iconfont icon-youjiantou1"></i>
          </div>
        </router-link>

        <van-cell title="">
          <div style="color: black">
            <span>共{{ sumNum(item.carts) }}件商品 实付</span
            ><span class="red">¥{{ item.allFee }}</span>
          </div>
        </van-cell>
        <van-cell
          title-style="color:gray"
          v-if="item.orderStatus === '00'"
          title="订单状态:已取消"
        >
          <button>重新购买</button>
        </van-cell>
        <van-cell
          title-style="color:gray"
          v-else-if="item.orderStatus === '01'"
          title="订单状态:已支付"
        >
          <button>取消订单</button>
        </van-cell>
        <van-cell title-class="f999" title-style="color:gray" v-else>
          <div slot="title" class="flex aic">
            <span class="mr-5">剩余支付时间:</span>
            <van-count-down
              :time="leftTime(item.createTime)"
              format="mm 分 ss 秒"
            />
          </div>
          <button @click="pay(item)">去支付</button>
        </van-cell>
      </div>
    </div>
  </div>
</template>

<script>
import $axios from "@/utils/index";
export default {
  data() {
    return {
      active: 0,
      orderList: [],
      onList: [],
      timer: null,
    };
  },
  methods: {
    async getOrderList() {
      try {
        let res = await $axios.get("order/all");
        console.log(res);
        this.orderList = res.list;
        this.onList = this.orderList;
      } catch (err) {
        console.log(err);
      }
    },
    sumNum(arr) {
      let s = 0;
      arr.forEach((item) => {
        s += item.buyNum;
      });
      return s;
    },
    leftTime(createTime) {
      return 15 * 60 * 1000 - (Date.now() - createTime);
    },
    switchTo(name, title) {
      if (title === "全部") {
        this.onList = this.orderList;
      } else if (title === "待付款") {
        this.onList = this.orderList.filter(
          (item) => item.orderStatus === "02"
        );
      } else if (title === "待发货") {
        this.onList = this.orderList.filter(
          (item) => item.orderStatus === "01"
        );
      } else {
        this.onList = this.orderList.filter(
          (item) => item.orderStatus === "00"
        );
      }
    },
    async pay(item) {
      try {
        let data = {
          orderId: item.orderId,
          allFee: item.totalMoney,
        };
        let res = await $axios.post("order/pay", data);
        // console.log(res)
        let query = {
          totalMoney: item.totalMoney,
          qrCode: res.result.qrcode,
          createTime: item.createTime,
          orderId: item.orderId,
        };
        this.$router.push({
          name: "pay",
          query: query,
        });
      } catch (err) {
        console.log(err);
      }
    },
  },
  computed: {},

  created() {
    this.getOrderList();
  },
};
</script>

<style lang='less'>
.order-wrap {
  .order {
    display: block;
  }
  .card {
    padding: 0 15px;
    .imgs {
      border-bottom: 1px solid #f4f4f4;
      padding: 15px 0;
      flex-wrap: nowrap;
      overflow-x: auto;
      &::-webkit-scrollbar {
        display: none; /* Chrome Safari */
      }
    }
    .iconfont {
      margin-left: auto;
    }
  }
  .product-img {
    background-color: #f9f9f9;
    width: 70px;
    height: 70px;
  }
}
</style>